import React, { useEffect, useState, useCallback } from 'react';
import { Outlet, NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../utils/api';

export default function Layout() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [unread, setUnread] = useState(0);
  const [notifications, setNotifications] = useState([]);
  const [showNotif, setShowNotif] = useState(false);

  const fetchNotifications = useCallback(() => {
    api.get('/notifications').then((r) => {
      setNotifications(r.data.notifications);
      setUnread(r.data.unreadCount);
    }).catch(() => {});
  }, []);

  useEffect(() => {
    fetchNotifications();
    const interval = setInterval(fetchNotifications, 30000);
    return () => clearInterval(interval);
  }, [fetchNotifications]);

  const handleMarkAllRead = () => {
    api.put('/notifications/read-all').then(() => {
      setUnread(0);
      setNotifications((n) => n.map((x) => ({ ...x, read: true })));
    });
  };

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <div className="d-flex">
      <nav className="sidebar d-flex flex-column">
        <div className="px-3 py-3 border-bottom border-secondary mb-2">
          <h5 className="mb-0 text-white">
            <i className="bi bi-heart-pulse-fill me-2 text-danger" />
            EHR System
          </h5>
          <small className="text-white-50">{user?.name}</small>
        </div>

        <NavLink to="/dashboard"><i className="bi bi-speedometer2 me-2" />Dashboard</NavLink>

        {(user?.role === 'admin' || user?.role === 'doctor') && (
          <NavLink to="/patients"><i className="bi bi-people me-2" />Patients</NavLink>
        )}

        <NavLink to="/appointments"><i className="bi bi-calendar-check me-2" />Appointments</NavLink>

        {(user?.role === 'admin' || user?.role === 'doctor') && (
          <NavLink to="/records/new"><i className="bi bi-file-earmark-plus me-2" />New Record</NavLink>
        )}

        <NavLink to="/vitals"><i className="bi bi-activity me-2" />Vitals</NavLink>

        {user?.role === 'patient' && (
          <NavLink to="/timeline"><i className="bi bi-clock-history me-2" />My Timeline</NavLink>
        )}

        {user?.role === 'admin' && (
          <NavLink to="/audit"><i className="bi bi-shield-check me-2" />Audit Logs</NavLink>
        )}

        <NavLink to="/profile"><i className="bi bi-person-circle me-2" />Profile</NavLink>

        <div className="mt-auto p-3">
          <button className="btn btn-outline-light btn-sm w-100" onClick={handleLogout}>
            <i className="bi bi-box-arrow-right me-2" />Logout
          </button>
        </div>
      </nav>

      <main className="main-content flex-grow-1">
        {/* Top bar with notifications */}
        <div className="d-flex justify-content-end align-items-center px-4 py-2 border-bottom bg-white position-relative">
          <div className="position-relative">
            <button
              className="btn btn-light btn-sm position-relative"
              onClick={() => setShowNotif((v) => !v)}
            >
              <i className="bi bi-bell fs-5" />
              {unread > 0 && (
                <span className="position-absolute top-0 start-100 translate-middle badge rounded-pill bg-danger">
                  {unread}
                </span>
              )}
            </button>

            {showNotif && (
              <div
                className="position-absolute end-0 mt-1 bg-white border rounded shadow"
                style={{ width: 320, zIndex: 1000, maxHeight: 400, overflowY: 'auto' }}
              >
                <div className="d-flex justify-content-between align-items-center px-3 py-2 border-bottom">
                  <strong>Notifications</strong>
                  {unread > 0 && (
                    <button className="btn btn-link btn-sm p-0" onClick={handleMarkAllRead}>
                      Mark all read
                    </button>
                  )}
                </div>
                {notifications.length === 0 ? (
                  <div className="text-center text-muted py-3 small">No notifications</div>
                ) : notifications.map((n) => (
                  <div
                    key={n._id}
                    className={`px-3 py-2 border-bottom ${!n.read ? 'bg-light' : ''}`}
                    style={{ cursor: 'pointer' }}
                    onClick={() => {
                      api.put(`/notifications/${n._id}/read`).catch(() => {});
                      setShowNotif(false);
                      if (n.link) navigate(n.link);
                    }}
                  >
                    <div className="fw-semibold small">{n.title}</div>
                    <div className="text-muted" style={{ fontSize: 12 }}>{n.message}</div>
                    <div className="text-muted" style={{ fontSize: 11 }}>
                      {new Date(n.createdAt).toLocaleString()}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        <div className="p-4">
          <Outlet />
        </div>
      </main>
    </div>
  );
}
